import{_ as a,o as n,c as s,aw as e}from"./chunks/framework.Dq2onT5h.js";const t=JSON.parse('{"title":"Architecture","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Architecture | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"overview/architecture.md","filePath":"overview/architecture.md","lastUpdated":1776419098000}');const o=a({name:"overview/architecture.md"},[["render",function(a,t,o,l,p,i){return n(),s("div",null,[...t[0]||(t[0]=[e('<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>Evolve uses a modular architecture where each component has a well-defined interface and can be swapped independently. This document provides an overview of how the pieces fit together.</p><h2 id="system-overview" tabindex="-1">System Overview <a class="header-anchor" href="#system-overview" aria-label="Permalink to &quot;System Overview&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>\n<span class="line"><span>│                          Client Apps                            │</span></span>\n<span class="line"><span>│                    (wallets, dapps, indexers)                   │</span></span>\n<span class="line"><span>└─────────────────────────────┬───────────────────────────────────┘</span></span>\n<span class="line"><span>                              │ JSON-RPC / gRPC</span></span>\n<span class="line"><span>┌─────────────────────────────▼───────────────────────────────────┐</span></span>\n<span class="line"><span>│                           ev-node                               │</span></span>\n<span class="line"><span>│  ┌───────────┐  ┌───────────┐  ┌───────────┐  ┌──────────────┐  │</span></span>\n<span class="line"><span>│  │  Block    │  │ Sequencer │  │    P2P    │  │    Sync      │  │</span></span>\n<span class="line"><span>│  │ Components│  │           │  │  Network  │  │   Services   │  │</span></span>\n<span class="line"><span>│  └─────┬─────┘  └─────┬─────┘  └─────┬─────┘  └───────┬──────┘  │</span></span>\n<span class="line"><span>└────────┼──────────────┼──────────────┼────────────────┼─────────┘</span></span>\n<span class="line"><span>         │              │              │                │</span></span>\n<span class="line"><span>         │ Executor     │ Sequencer    │ libp2p        │ DA Client</span></span>\n<span class="line"><span>         ▼              ▼              ▼                ▼</span></span>\n<span class="line"><span>┌────────────────┐ ┌──────────┐ ┌─────────────────────────────────┐</span></span>\n<span class="line"><span>│    Executor    │ │Sequencer │ │          DA Layer               │</span></span>\n<span class="line"><span>│  (ev-reth or   │ │(single,  │ │         (Celestia)              │</span></span>\n<span class="line"><span>│   ev-abci)     │ │ based)   │ │                                 │</span></span>\n<span class="line"><span>└────────────────┘ └──────────┘ └─────────────────────────────────┘</span></span></code></pre></div><h2 id="core-design-principles" tabindex="-1">Core Design Principles <a class="header-anchor" href="#core-design-principles" aria-label="Permalink to &quot;Core Design Principles&quot;">​</a></h2><ol><li><p><strong>Zero-dependency core</strong> — The <code>core/</code> package contains only interfaces with no external dependencies. This keeps the API stable and allows any implementation.</p></li><li><p><strong>Modular components</strong> — Executor, Sequencer, and DA layer are all pluggable. Swap them without changing ev-node.</p></li><li><p><strong>Separation of concerns</strong> — Block production, syncing, and DA submission run as independent components that communicate through well-defined channels.</p></li><li><p><strong>Two operating modes</strong> — Nodes run as either an Aggregator (produces blocks) or Sync-only (follows chain).</p></li></ol><h2 id="block-components" tabindex="-1">Block Components <a class="header-anchor" href="#block-components" aria-label="Permalink to &quot;Block Components&quot;">​</a></h2><p>The block package is the heart of ev-node. It&#39;s organized into specialized components:</p><table tabindex="0"><thead><tr><th>Component</th><th>Responsibility</th><th>Runs On</th></tr></thead><tbody><tr><td><strong>Executor</strong></td><td>Produces blocks by getting batches from sequencer and executing via execution layer</td><td>Aggregator only</td></tr><tr><td><strong>Reaper</strong></td><td>Scrapes transactions from execution layer mempool and submits to sequencer</td><td>Aggregator only</td></tr><tr><td><strong>Syncer</strong></td><td>Coordinates block sync from DA layer and P2P network</td><td>All nodes</td></tr><tr><td><strong>Submitter</strong></td><td>Submits blocks to DA layer and tracks inclusion</td><td>Aggregator only</td></tr><tr><td><strong>Cache</strong></td><td>Manages in-memory state for headers, data, and pending submissions</td><td>All nodes</td></tr></tbody></table><h3 id="component-interaction" tabindex="-1">Component Interaction <a class="header-anchor" href="#component-interaction" aria-label="Permalink to &quot;Component Interaction&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    ┌─────────────┐</span></span>\n<span class="line"><span>                    │   Reaper    │</span></span>\n<span class="line"><span>                    │  (tx scrape)│</span></span>\n<span class="line"><span>                    └──────┬──────┘</span></span>\n<span class="line"><span>                           │ Submit batch</span></span>\n<span class="line"><span>                           ▼</span></span>\n<span class="line"><span>┌─────────────┐    ┌─────────────┐    ┌─────────────┐</span></span>\n<span class="line"><span>│  Sequencer  │◄───│  Executor   │───►│ Broadcaster │</span></span>\n<span class="line"><span>│             │    │(block prod) │    │   (P2P)     │</span></span>\n<span class="line"><span>└─────────────┘    └──────┬──────┘    └─────────────┘</span></span>\n<span class="line"><span>                          │</span></span>\n<span class="line"><span>                          │ Queue for submission</span></span>\n<span class="line"><span>                          ▼</span></span>\n<span class="line"><span>                   ┌─────────────┐</span></span>\n<span class="line"><span>                   │  Submitter  │───► DA Layer</span></span>\n<span class="line"><span>                   │             │</span></span>\n<span class="line"><span>                   └──────┬──────┘</span></span>\n<span class="line"><span>                          │</span></span>\n<span class="line"><span>                          │ Track inclusion</span></span>\n<span class="line"><span>                          ▼</span></span>\n<span class="line"><span>                   ┌─────────────┐</span></span>\n<span class="line"><span>                   │    Cache    │</span></span>\n<span class="line"><span>                   └─────────────┘</span></span></code></pre></div><h2 id="node-types" tabindex="-1">Node Types <a class="header-anchor" href="#node-types" aria-label="Permalink to &quot;Node Types&quot;">​</a></h2><p>Evolve supports several node configurations:</p><table tabindex="0"><thead><tr><th>Type</th><th>Block Production</th><th>Full Validation</th><th>DA Submission</th><th>Use Case</th></tr></thead><tbody><tr><td><strong>Aggregator</strong></td><td>Yes</td><td>Yes</td><td>Yes</td><td>Block producer (sequencer)</td></tr><tr><td><strong>Full Node</strong></td><td>No</td><td>Yes</td><td>No</td><td>RPC provider, validator</td></tr><tr><td><strong>Light Node</strong></td><td>No</td><td>Headers only</td><td>No</td><td>Mobile, embedded clients</td></tr><tr><td><strong>Attester</strong></td><td>No</td><td>Yes</td><td>No</td><td>Soft consensus participant</td></tr></tbody></table><h3 id="aggregator" tabindex="-1">Aggregator <a class="header-anchor" href="#aggregator" aria-label="Permalink to &quot;Aggregator&quot;">​</a></h3><p>The aggregator (also called sequencer node) produces blocks:</p><ol><li>Reaper collects transactions from execution layer</li><li>Executor gets ordered batch from sequencer</li><li>Executor calls execution layer to process transactions</li><li>Executor creates and signs block (header + data)</li><li>Broadcaster gossips block to P2P network</li><li>Submitter queues block for DA submission</li></ol><h3 id="full-node" tabindex="-1">Full Node <a class="header-anchor" href="#full-node" aria-label="Permalink to &quot;Full Node&quot;">​</a></h3><p>Full nodes sync and validate without producing blocks:</p><ol><li>Syncer receives blocks from DA layer and/or P2P</li><li>Validates header signatures and data hashes</li><li>Executes transactions via execution layer</li><li>Verifies resulting state root matches header</li><li>Persists validated blocks to local store</li></ol><h2 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data Flow&quot;">​</a></h2><h3 id="block-production-aggregator" tabindex="-1">Block Production (Aggregator) <a class="header-anchor" href="#block-production-aggregator" aria-label="Permalink to &quot;Block Production (Aggregator)&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User Tx → Execution Layer Mempool</span></span>\n<span class="line"><span>                 │</span></span>\n<span class="line"><span>                 ▼</span></span>\n<span class="line"><span>         Reaper scrapes txs</span></span>\n<span class="line"><span>                 │</span></span>\n<span class="line"><span>                 ▼</span></span>\n<span class="line"><span>         Sequencer orders batch</span></span>\n<span class="line"><span>                 │</span></span>\n<span class="line"><span>                 ▼</span></span>\n<span class="line"><span>         Executor.ExecuteTxs()</span></span>\n<span class="line"><span>                 │</span></span>\n<span class="line"><span>                 ├──► SignedHeader + Data</span></span>\n<span class="line"><span>                 │</span></span>\n<span class="line"><span>                 ├──► P2P Broadcast (soft confirmation)</span></span>\n<span class="line"><span>                 │</span></span>\n<span class="line"><span>                 └──► Submitter Queue</span></span>\n<span class="line"><span>                           │</span></span>\n<span class="line"><span>                           ▼</span></span>\n<span class="line"><span>                      DA Layer (hard confirmation)</span></span></code></pre></div><h3 id="block-sync-non-aggregator" tabindex="-1">Block Sync (Non-Aggregator) <a class="header-anchor" href="#block-sync-non-aggregator" aria-label="Permalink to &quot;Block Sync (Non-Aggregator)&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────┐</span></span>\n<span class="line"><span>│              Syncer                    │</span></span>\n<span class="line"><span>├────────────┬────────────┬──────────────┤</span></span>\n<span class="line"><span>│ DA Worker  │ P2P Worker │Forced Incl.  │</span></span>\n<span class="line"><span>│            │            │   Worker     │</span></span>\n<span class="line"><span>└─────┬──────┴─────┬──────┴───────┬──────┘</span></span>\n<span class="line"><span>      │            │              │</span></span>\n<span class="line"><span>      └────────────┴──────────────┘</span></span>\n<span class="line"><span>                   │</span></span>\n<span class="line"><span>                   ▼</span></span>\n<span class="line"><span>           processHeightEvent()</span></span>\n<span class="line"><span>                   │</span></span>\n<span class="line"><span>                   ▼</span></span>\n<span class="line"><span>           Validate → Execute → Persist</span></span></code></pre></div><h2 id="p2p-network" tabindex="-1">P2P Network <a class="header-anchor" href="#p2p-network" aria-label="Permalink to &quot;P2P Network&quot;">​</a></h2><p>Built on libp2p with:</p><ul><li><strong>FloodSub</strong> for transaction and block propagation</li><li><strong>Kademlia DHT</strong> for peer discovery</li><li><strong>Topics</strong>: <code>{chainID}-tx</code>, <code>{chainID}-header</code>, <code>{chainID}-data</code></li></ul><p>Nodes discover peers through:</p><ol><li>Bootstrap/seed nodes</li><li>DHT peer exchange</li><li>PEX (peer exchange protocol)</li></ol><h2 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Storage&quot;">​</a></h2><p>ev-node uses a key-value store (badger) for:</p><ul><li><strong>Headers</strong> — Indexed by height and hash</li><li><strong>Data</strong> — Transaction lists indexed by height</li><li><strong>State</strong> — Last committed height, app hash, DA height</li><li><strong>Pending</strong> — Blocks awaiting DA inclusion</li></ul><h2 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further Reading&quot;">​</a></h2><ul><li><a href="/concepts/block-lifecycle">Block Lifecycle</a> — Detailed block processing flow</li><li><a href="/concepts/sequencing">Sequencing</a> — How transaction ordering works</li><li><a href="/concepts/data-availability">Data Availability</a> — DA layer integration</li><li><a href="/reference/interfaces/executor">Executor Interface</a> — Full interface reference</li></ul>',35)])])}]]);export{t as __pageData,o as default};
